     4â†’
     5â†’import { basename } from 'node:path'
     6â†’
     7â†’import type { ManifestEntry } from '../../types/transcript.js'
     8â†’import type { Translations } from '../i18n/types.js'
     9â†’import { REPORT_CSS } from './css.js'
    10â†’
    11â†’// ---------------------------------------------------------------------------
    12â†’// HTML escaping
    13â†’// ---------------------------------------------------------------------------
    14â†’
    15â†’export function escHtml(text: string): string {
    16â†’  return text
    17â†’    .replace(/&/g, '&amp;')
    18â†’    .replace(/</g, '&lt;')
    19â†’    .replace(/>/g, '&gt;')
    20â†’    .replace(/"/g, '&quot;')
    21â†’    .replace(/'/g, '&#39;')
    22â†’}
    23â†’
    24â†’// ---------------------------------------------------------------------------
    25â†’// Navigation page IDs
    26â†’// ---------------------------------------------------------------------------
    27â†’
    28â†’export type NavPage =
    29â†’  | 'dashboard'
    30â†’  | 'transcripts'
    31â†’  | 'projects'
    32â†’  | 'graph'
    33â†’  | 'goals'
    34â†’  | 'todos'
    35â†’  | 'knowledge'
    36â†’  | 'archive'
    37â†’  | 'search'
    38â†’
    39â†’// ---------------------------------------------------------------------------
    40â†’// Sidebar navigation
    41â†’// ---------------------------------------------------------------------------
    42â†’
    43â†’const SIDEBAR_INLINE_JS = `
    44â†’<script>
    45â†’(function() {
    46â†’  // Theme
    47â†’  var saved = localStorage.getItem('mt-theme') || 'dark';
    48â†’  document.documentElement.setAttribute('data-theme', saved);
    49â†’  function updateThemeBtn() {
    50â†’    var btn = document.getElementById('theme-toggle');
    51â†’    if (btn) btn.textContent = document.documentElement.getAttribute('data-theme') === 'dark' ? 'âک€ Light' : 'âک¾ Dark';
    52â†’  }
    53â†’  document.addEventListener('DOMContentLoaded', function() {
    54â†’    updateThemeBtn();
    55â†’    var btn = document.getElementById('theme-toggle');
    56â†’    if (btn) btn.addEventListener('click', function() {
    57â†’      var next = document.documentElement.getAttribute('data-theme') === 'dark' ? 'light' : 'dark';
    58â†’      document.documentElement.setAttribute('data-theme', next);
    59â†’      localStorage.setItem('mt-theme', next);
    60â†’      updateThemeBtn();
    61â†’    });
    62â†’    // Mobile hamburger
    63â†’    var hb = document.getElementById('hamburger');
    64â†’    var sb = document.getElementById('sidebar');
    65â†’    var ov = document.getElementById('sidebar-overlay');
    66â†’    function closeSidebar() {
    67â†’      if (sb) sb.classList.remove('open');
    68â†’      if (ov) ov.classList.remove('open');
    69â†’    }
    70â†’    if (hb) hb.addEventListener('click', function() {
    71â†’      if (sb) sb.classList.toggle('open');
    72â†’      if (ov) ov.classList.toggle('open');
    73â†’    });
    74â†’    if (ov) ov.addEventListener('click', closeSidebar);
    75â†’    // Popover preview
    76â†’    var popover = null;
    77â†’    document.querySelectorAll('a[data-summary]').forEach(function(el) {
    78â†’      el.addEventListener('mouseenter', function(e) {
    79â†’        var summary = el.getAttribute('data-summary') || '';
    80â†’        var meta = el.getAttribute('data-meta') || '';
    81â†’        if (!summary && !meta) return;
    82â†’        if (!popover) {
    83â†’          popover = document.createElement('div');
    84â†’          popover.className = 'popover';
    85â†’          document.body.appendChild(popover);
    86â†’        }
    87â†’        popover.innerHTML = '';
    88â†’        if (meta) {
    89â†’          var metaDiv = document.createElement('div');
    90â†’          metaDiv.className = 'popover-meta';
    91â†’          metaDiv.textContent = meta;
    92â†’          popover.appendChild(metaDiv);
    93â†’        }
    94â†’        if (summary) {
    95â†’          var sumDiv = document.createElement('div');
    96â†’          sumDiv.className = 'popover-summary';
    97â†’          sumDiv.textContent = summary;
    98â†’          popover.appendChild(sumDiv);
    99â†’        }
   100â†’        popover.style.display = 'block';
   101â†’        positionPopover(e);
   102â†’      });
   103â†’      el.addEventListener('mousemove', positionPopover);
   104â†’      el.addEventListener('mouseleave', function() {
   105â†’        if (popover) popover.style.display = 'none';
   106â†’      });
   107â†’    });
   108â†’    function positionPopover(e) {
   109â†’      if (!popover) return;
   110â†’      var x = e.clientX + 12;
   111â†’      var y = e.clientY + 12;
   112â†’      var pw = popover.offsetWidth || 320;
   113â†’      var ph = popover.offsetHeight || 80;
   114â†’      if (x + pw > window.innerWidth - 8) x = e.clientX - pw - 12;
   115â†’      if (y + ph > window.innerHeight - 8) y = e.clientY - ph - 12;
   116â†’      popover.style.left = x + 'px';
   117â†’      popover.style.top = y + 'px';
