   123â†’interface NavItem {
   124â†’  id: NavPage
   125â†’  icon: string
   126â†’  labelKey: keyof Translations['nav']
   127â†’  href: string
   128â†’}
   129â†’
   130â†’function buildNavItems(depth: 0 | 1 | 2): NavItem[] {
   131â†’  const p = '../'.repeat(depth)
   132â†’  return [
   133â†’    { id: 'dashboard', icon: 'â—ˆ', labelKey: 'dashboard', href: `${p}index.html` },
   134â†’    { id: 'transcripts', icon: 'ًں’¬', labelKey: 'sessions', href: `${p}transcripts/index.html` },
   135â†’    { id: 'projects', icon: 'ًں“پ', labelKey: 'projects', href: `${p}projects/index.html` },
   136â†’    { id: 'graph', icon: 'â¬،', labelKey: 'graph', href: `${p}graph.html` },
   137â†’    { id: 'goals', icon: 'ًںژ¯', labelKey: 'goals', href: `${p}goals/index.html` },
   138â†’    { id: 'todos', icon: 'âœ“', labelKey: 'todos', href: `${p}todos/index.html` },
   139â†’    { id: 'knowledge', icon: 'ًں“ڑ', labelKey: 'knowledge', href: `${p}knowledge/index.html` },
   140â†’    { id: 'archive', icon: 'ًں—„', labelKey: 'archive', href: `${p}archive/index.html` },
   141â†’    { id: 'search', icon: 'ًں”چ', labelKey: 'search', href: `${p}search.html` },
   142â†’  ]
   143â†’}
   144â†’
   145â†’export function renderNav(current: NavPage, depth: 0 | 1 | 2, t?: Translations): string {
   146â†’  const items = buildNavItems(depth)
   147â†’
   148â†’  // Labels for each nav item
   149â†’  const label = (item: NavItem): string => {
   150â†’    if (t) return t.nav[item.labelKey]
   151â†’    // Fallback English labels
   152â†’    const defaults: Record<string, string> = {
   153â†’      dashboard: 'Dashboard', sessions: 'Sessions', projects: 'Projects',
   154â†’      graph: 'Graph', goals: 'Goals', todos: 'Todos',
   155â†’      knowledge: 'Knowledge', archive: 'Archive', search: 'Search',
   156â†’    }
   157â†’    return defaults[item.labelKey] ?? item.labelKey
   158â†’  }
   159â†’
   160â†’  const themeLabel = 'âک€ Light'
   161â†’
   162â†’  const navLinks = items.map(item => {
   163â†’    const cls = item.id === current ? 'nav-link active' : 'nav-link'
   164â†’    return `<a href="${escHtml(item.href)}" class="${cls}">${escHtml(item.icon)} ${escHtml(label(item))}</a>`
   165â†’  }).join('\n      ')
   166â†’
   167â†’  return `<aside class="sidebar" id="sidebar">
   168â†’  <div class="sidebar-header">
   169â†’    <span class="sidebar-brand">MemoryTree</span>
   170â†’  </div>
   171â†’  <nav class="sidebar-nav">
   172â†’    ${navLinks}
   173â†’  </nav>
   174â†’  <div class="sidebar-footer">
   175â†’    <button class="theme-toggle-btn" id="theme-toggle" type="button">${escHtml(themeLabel)}</button>
   176â†’  </div>
   177â†’</aside>
   178â†’<div class="sidebar-overlay" id="sidebar-overlay"></div>`
   179â†’}
   180â†’
   181â†’// ---------------------------------------------------------------------------
   182â†’// HTML shell
   183â†’// ---------------------------------------------------------------------------
   184â†’
   185â†’// ---------------------------------------------------------------------------
   186â†’// Transcript URL helpers (single canonical implementation)
   187â†’// ---------------------------------------------------------------------------
   188â†’
   189â†’/**
   190â†’ * Compute the stem (filename without .md) for a manifest's clean path.
   191â†’ * Falls back to session_id.
   192â†’ */
   193â†’export function manifestStem(m: ManifestEntry): string {
   194â†’  const cleanPath = m.repo_clean_path || m.global_clean_path || ''
   195â†’  return cleanPath ? basename(cleanPath, '.md') : m.session_id
   196â†’}
