   202â†’export function transcriptUrlFromRoot(m: ManifestEntry): string {
   203â†’  return `transcripts/${m.client}/${manifestStem(m)}.html`
   204â†’}
   205â†’
   206â†’/**
   207â†’ * URL to a transcript page relative to **another transcript** page.
   208â†’ * Use this from individual transcript pages.
   209â†’ */
