   216â†’// ---------------------------------------------------------------------------
   217â†’
   218â†’const KNOWN_CLIENTS = new Set(['codex', 'claude', 'gemini'])
   219â†’
   220â†’/** Render a coloured client badge. CSS class is allowlisted to prevent injection. */
   221â†’export function clientBadge(client: string): string {
   222â†’  const safeClass = KNOWN_CLIENTS.has(client) ? client : 'unknown'
   223â†’  return `<span class="badge badge-${safeClass}">${escHtml(client)}</span>`
   224â†’}
