   226â†’// ---------------------------------------------------------------------------
   227â†’// Shared MarkdownFile type and slug helper
   228â†’// ---------------------------------------------------------------------------
   229â†’
   230â†’export interface MarkdownFile {
   231â†’  filename: string
   232â†’  title: string
   233â†’  content: string
   234â†’}
   235â†’
   236â†’export function slugifyName(name: string): string {
   237â†’  return name.toLowerCase().replace(/[^a-z0-9]+/g, '-')
   238â†’}
   239â†’
   240â†’// ---------------------------------------------------------------------------
   241â†’// HTML shell
   242â†’// ---------------------------------------------------------------------------
   243â†’
   244â†’export function htmlShell(title: string, content: string, nav: string, extraHead = '', lang = 'en'): string {
   245â†’  const topbar = `<header class="topbar" id="topbar">
   246â†’  <span class="topbar-brand">MemoryTree</span>
   247â†’  <div class="topbar-actions">
   248â†’    <button class="theme-toggle-btn" id="theme-toggle-mobile" type="button">âک€</button>
   249â†’    <button class="hamburger" id="hamburger" type="button">âک°</button>
   250â†’  </div>
   251â†’</header>`
   252â†’
   253â†’  return `<!DOCTYPE html>
   254â†’<html lang="${escHtml(lang)}" data-theme="dark">
   255â†’<head>
   256â†’<meta charset="UTF-8">
   257â†’<meta name="viewport" content="width=device-width, initial-scale=1.0">
   258â†’<title>${escHtml(title)} â€” MemoryTree</title>
   259â†’<style>${REPORT_CSS}</style>
   260â†’${extraHead}
   261â†’${SIDEBAR_INLINE_JS}
   262â†’</head>
   263â†’<body>
   264â†’${topbar}
   265â†’${nav}
   266â†’<div class="main-content">
   267â†’  <div class="container">
   268â†’${content}
   269â†’  </div>
   270â†’</div>
   271â†’</body>
   272â†’</html>`
   273â†’}
